INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-c5fb3965-moex-00151', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '戶籍登記後發生訴訟，經和解成立後應為更正登記，戶政事務所以書面催 告後仍不申請時，應如何處理？', '["戶政事務所應依職權逕為登記，並應於登記後通知利害關係人", "戶政事務所應依職權逕為登記，並應於登記後通知本人", "戶政事務所應對本人處以罰鍰，直到本人申請為止", "戶政事務所應以書面催告二次後，始得依職權逕為登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00152', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '關於戶籍登記時，申請人應提出證明文件正本之事項，下列敘述何者正 確？', '["於民國97年5月22日以前結婚，雙方當事人與兩人以上親見公開儀式 之證人親自辦理登記者，得免提結婚證明文件", "辦理出生登記，如出生於國外者，得免提出證明文件正本", "辦理未成年子女權利義務行使負擔登記時，其父母婚姻經撤銷者，得免 提出裁判確定判決書正本", "辦理認領登記時，如被認領人出生於國外，得免提出血緣鑑定證明書"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00153', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '某甲與某乙在國內均設有戶籍，2人於民國97年2月14日已在國內舉行 公開儀式結婚宴客，迄未辦理結婚登記，現欲向戶政事務所申請結婚證明 書，應如何辦理？', '["因結婚已生效，可逕向任一戶政事務所申請結婚證明書", "應由甲與乙一同到戶政事務所辦理結婚登記後，再申請結婚證明書", "可由甲或乙其中一人到戶政事務所辦理結婚登記後，再申請結婚證明書", "因結婚已生效，可直接委託他人，無須經戶政事務所同意，即可向戶政 事務所辦理結婚登記後，再申請結婚證明書"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00154', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '下列戶籍登記，何者無須戶政事務所同意，即得委託他人辦理？', '["結婚登記", "認領登記", "兩願離婚登記", "遷徙登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00155', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '下列何者屬免經催告程序，得由戶政事務所逕行辦理之戶籍登記？', '["監護登記", "死亡宣告登記", "死亡登記", "輔助登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00156', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '戶籍法規定，本人或利害關係人得向戶政事務所申請閱覽戶籍資料或交付 戶籍謄本。下列何者非屬於利害關係人？', '["與當事人同為公司合夥人", "與當事人之債務未清償者", "為當事人之兄弟姊妹", "與當事人為訴訟繫屬中之兩造當事人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00157', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '出生登記當事人之姓氏，依相關法律規定未能確定時，應如何辦理？', '["婚生子女，以抽籤決定依父姓或母姓登記", "非婚生子女，依監護人之姓登記", "無依兒童，依安置之兒童及少年福利機構負責人之姓登記", "能確定生父者，一律依父姓登記"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00158', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '國人王先生不幸於加拿大遭遇車禍死亡，其死亡證明書所載明的日期為加 拿大當地日期，死亡登記所登載之日期應如何因應？', '["不須轉換證明書之日期，因採西元紀年日期已足以辨識", "必須將證明書之當地日期轉換為國內日期（民國紀年）", "不須轉換證明書之日期，但得於戶籍登記記事載明", "為避免轉換日期爭議，一律以申請死亡登記之日為死亡日期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00159', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '下列關於國民身分證換領之方式，何者錯誤？', '["申請戶籍登記致國民身分證記載事項變更者，向各該申請登記之戶政事 務所申請", "更換相片，向任一戶政事務所申請", "國民身分證之役別記載變更，應申請換領", "全面換領，向戶籍地戶政事務所申請"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00160', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-bdc7da1c', 'sub-disabled-c5fb3965-04', NULL, 'single_choice', '甲的國民身分證不慎於洗衣時毀損，依戶籍法應如何處理？', '["甲得向戶籍地戶政事務所申請補領國民身分證", "甲應於下次辦理戶籍登記時一併申請換領國民身分證", "甲得向任一戶政事務所申請換領國民身分證", "甲得以書面或經網路向內政部聲明作廢舊國民身分證並同時申請換領"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "0bf95e5249ec", "answer_pdf_sha1": "4568d7e6b3e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
